import { getTypedInterfaceState } from "./gameInterface/interfaceState";
import { getCurrentRadioContext } from "./UIfacade/radioFacade";
if (getCurrentRadioContext().channel === getTypedInterfaceState().selectedRadioChannel /* trick to prevent displaying messages of the previously selected channel */) {
  return Context.interfaceState.state.radioMessageInput[getCurrentRadioContext().channel] || '';
}
