import { getSendRadioMessageTemplate } from "./game/common/actions/actionLogic";
import { isPlannedAction } from "./gameInterface/main";
import { getTranslation } from "./tools/translation";
import { getCurrentRadioContext } from "./UIfacade/radioFacade";
const action = getSendRadioMessageTemplate(getCurrentRadioContext().channel);
